// ---- Vyapaar-AI: n8n Negotiation Logic ----
const msg = $input.item.json.message;
const chatId = String(msg.chat.id);
const text = msg.text || '';

// Product config - change these per product
const MRP = 1500;
const MIN_PRICE = 1100;

// Extract price from message
const priceMatch = text.match(/\d+/);
const customerOffer = priceMatch ? parseInt(priceMatch[0]) : null;

// Retrieve session turn count from static data
const staticData = $getWorkflowStaticData('node');
const sessionKey = `turn_${chatId}`;
let turnCount = staticData[sessionKey] || 1;

// ---- Negotiation Rules ----
let status, reply, counterOffer;

if (!customerOffer) {
  // No price in message - check intent keywords
  const lower = text.toLowerCase();
  const agreeWords = ['done', 'theek hai', 'pakka', 'confirm', 'bhej do', 'le lunga'];
  const isAgree = agreeWords.some(w => lower.includes(w));

  if (isAgree) {
    status = 'SOLD';
    reply = `Deal pakka sir! Payment link bhej raha hun.`;
    delete staticData[sessionKey];
  } else {
    status = 'NEGOTIATING';
    reply = `Bhaiya price batao, deal karte hain. Yeh product Rs.${MRP} ka hai.`;
  }
} else if (customerOffer >= MRP) {
  status = 'SOLD';
  reply = `Done sir! Rs.${MRP} mein pakka. Payment link abhi bhej raha hun.`;
  delete staticData[sessionKey];
} else if (customerOffer >= MIN_PRICE && turnCount >= 2) {
  status = 'SOLD';
  reply = `Chaliye theek hai! Rs.${customerOffer} mein final karte hain.`;
  delete staticData[sessionKey];
} else if (customerOffer < MIN_PRICE) {
  if (turnCount >= 3) {
    status = 'WALKAWAY';
    reply = `Bhaiya, Rs.${MIN_PRICE} se ek paisa bhi kam nahi hoga. Last price yahi hai.`;
    delete staticData[sessionKey];
  } else {
    const discount = (MRP - MIN_PRICE) * (0.3 * turnCount);
    counterOffer = Math.round(MRP - discount);
    status = 'NEGOTIATING';
    reply = `Arey sir, Rs.${customerOffer} mein cost bhi nahi niklega! Chalo Rs.${counterOffer} final kar deta hun.`;
    staticData[sessionKey] = turnCount + 1;
  }
} else {
  counterOffer = Math.round((customerOffer + MRP) / 2);
  status = 'NEGOTIATING';
  reply = `Sir Rs.${customerOffer} mein thoda tough hai. Rs.${counterOffer} kar dijiye!`;
  staticData[sessionKey] = turnCount + 1;
}

return { json: { chatId, reply, status, counterOffer } };
